 92→function truncateContent(content: string, maxLength: number): string {
 93→  const singleLine = content.replace(/\n/g, ' ');
 94→  if (singleLine.length <= maxLength) return singleLine;
 95→  return singleLine.slice(0, maxLength) + '\u2026';
 96→}
