21→export function storageSet<T>(key: string, value: T): void {
22→  try {
23→    localStorage.setItem(prefixKey(key), JSON.stringify(value));
24→  } catch {
25→    // localStorage unavailable
26→  }
27→}
28→
29→export function storageRemove(key: string): void {
30→  try {
31→    localStorage.removeItem(prefixKey(key));
32→  } catch {
33→    // localStorage unavailable
34→  }
35→}
